@startuml
' --- Styling and Configuration ---
skinparam componentStyle rectangle
top to bottom direction

skinparam package {
    BackgroundColor White
    BorderColor #333333
}

' Defining styles based on Mermaid classDefs
skinparam rectangle<<frontend>> {
    BackgroundColor #d4e6f1
    BorderColor #2874a6
    BorderThickness 2
}

skinparam rectangle<<present>> {
    BackgroundColor #f9e79f
    BorderColor #d4ac0d
    BorderThickness 2
}

skinparam rectangle<<business>> {
    BackgroundColor #abebc6
    BorderColor #1d8348
    BorderThickness 2
}

skinparam rectangle<<data>> {
    BackgroundColor #d7bde2
    BorderColor #884ea0
    BorderThickness 2
}

skinparam database<<db>> {
    BackgroundColor #fdfefe
    BorderColor #333333
    BorderThickness 2
}

skinparam rectangle<<sidebar>> {
    BackgroundColor #f1948a
    BorderColor #cb4335
    BorderThickness 2
}

skinparam rectangle<<logbar>> {
    BackgroundColor #a9cce3
    BorderColor #2471a3
    BorderThickness 2
}

' --- Architecture Layers ---

package "Frontend UI Layer" as FrontendUI {
    rectangle "TypeScript" as TS <<frontend>>
    rectangle "Vite2" as Vite <<frontend>>
    rectangle "Vue3" as Vue <<frontend>>
    rectangle "element-plus" as Elem <<frontend>>
}

package "Presentation Layer" as Presentation {
    rectangle "Template Rendering" as Render <<present>>

    rectangle "Ajax Interaction" as AjaxGroup <<present>> {
        rectangle "POST Request" as PostReq <<present>>
        rectangle "GET Request" as GetReq <<present>>
    }
}

package "Business Layer" as BusinessLayer {
    rectangle "Spring Boot" as SB_Container <<business>> {
        rectangle "Community Management" as CommMgmt <<business>>
        rectangle "User Management" as UserMgmt <<business>>
        rectangle "Game System" as GameSys <<business>>
        rectangle "Favorites Module" as FavMod <<business>>
        rectangle "Notification Module" as NotifMod <<business>>

    }
}

' Side Components
rectangle "Log Recording" as LogRec <<logbar>>
rectangle "Permission Control" as AuthCtrl <<sidebar>>

package "Data Layer" as DataLayer {
    rectangle "Data Caching" as Cache <<data>>
    rectangle "Read/Write Database" as RWDB <<data>>
    rectangle "Storage" as Storage <<data>>

}

package "Database Layer" as DatabaseLayer {
    database "MySQL" as MySQL <<db>>
}

' --- Relationships ---

FrontendUI --> Presentation
BusinessLayer --> Render
BusinessLayer --> DataLayer
DataLayer --> MySQL

AjaxGroup --> BusinessLayer

' Dotted relationships for cross-cutting concerns
BusinessLayer .. LogRec
BusinessLayer .. AuthCtrl
DataLayer .. LogRec
DataLayer .. AuthCtrl
Presentation .. AuthCtrl

@enduml

@startuml
' --- Configuration & Styles ---
skinparam TitleFontSize 20
skinparam Nodesep 50
skinparam Ranksep 50
left to right direction

' Style Definitions (Mapping Mermaid classDef)
skinparam rectangle {
    BackgroundColor<<security>> #ffebee
    BorderColor<<security>> #c62828
    BackgroundColor<<gateway>> #e8f5e9
    BorderColor<<gateway>> #2e7d32
    BackgroundColor<<static>> #fce4ec
    BorderColor<<static>> #880e4f
    BackgroundColor<<microservice>> #e3f2fd
    BorderColor<<microservice>> #1565c0
    BackgroundColor<<infra>> #fff3e0
    BorderColor<<infra>> #ef6c00
}

skinparam database {
    BackgroundColor<<infra>> #fff3e0
    BorderColor<<infra>> #ef6c00
}

title Awesome Music System

package "Awesome Music System" {

    ' Zone 1: Security Critical Zone
    rectangle "Security Critical Zone" as Security_Zone {

        rectangle "Nginx Cluster" as Nginx_Cluster {
            rectangle "Nginx1" as Nginx1 <<security>>
            rectangle "Nginx2" as Nginx2 <<security>>
            rectangle "Nginx3" as Nginx3 <<security>>
        }

        rectangle "Static Resource Server" as Static_Server {
            rectangle "Static Server1" as Static1 <<static>>
            rectangle "Static Server2" as Static2 <<static>>
            rectangle "Static Server3" as Static3 <<static>>
        }

        rectangle "Spring Cloud Gateway" as Gateway_Cluster {
            rectangle "gateway1" as GW1 <<gateway>>
            rectangle "gateway2" as GW2 <<gateway>>
            rectangle "gateway3" as GW3 <<gateway>>
        }
    }

    ' Zone 2: Micro Service Layer
    rectangle "Micro Service Layer" as Micro_Service_Layer {

        rectangle "service-auth" as Svc_Auth {
            rectangle "auth1" as Auth1 <<microservice>>
            rectangle "auth2" as Auth2 <<microservice>>
            rectangle "auth3" as Auth3 <<microservice>>
        }

        rectangle "service-web" as Svc_Web {
            rectangle "web1" as Web1 <<microservice>>
            rectangle "web2" as Web2 <<microservice>>
            rectangle "web3" as Web3 <<microservice>>
        }

        rectangle "service-scheduler" as Svc_Sched {
            rectangle "scheduler1" as Sch1 <<microservice>>
            rectangle "scheduler2" as Sch2 <<microservice>>
            rectangle "scheduler3" as Sch3 <<microservice>>
        }

        rectangle "service-discovery" as Svc_Disc {
            rectangle "discovery1" as Disc1 <<microservice>>
            rectangle "discovery2" as Disc2 <<microservice>>
            rectangle "discovery3" as Disc3 <<microservice>>
        }
    }

    ' Zone 3: Infra Layer
    rectangle "Infra Layer" as Infra_Layer {
        database "MySQL" as MySQL <<infra>>
        database "Redis" as Redis <<infra>>
        rectangle "RabbitMQ" as RabbitMQ <<infra>>
        rectangle "Prometheus" as Prometheus <<infra>>
    }

}

' --- Relationships ---
Gateway_Cluster --> Micro_Service_Layer
Micro_Service_Layer --> Infra_Layer

@enduml

