@startuml
!theme plain
skinparam defaultTextAlignment center

skinparam package {
    BorderThickness 1.5
}

package "Annotation Models" as AM #F8F0FA {
    rectangle "Entity Model - ChatGPT/\nLLM" as entity
    rectangle "Paragraph Model - Google\nBERT" as para
}

package "Infrastructure Layer" as Infra #EEF1F3 {
    rectangle "Tencent Cloud Server" as tencent
    rectangle "Docker Containerization" as docker
    rectangle "RabbitMQ Message Queue" as rabbitmq
}

package "Application Layer-Ant\nDesign / Vue.js" as App #FFA6FF {
    rectangle "Preset Sharing" as preset
    rectangle "Text Annotation" as annotation
    rectangle "Intelligent Mining" as mining
}

package "Gateway Layer" as Gateway #FFF5D6 {
    rectangle "Nginx Gateway" as nginx
}

package "Business Service Layer-\nSpring Boot" as Biz #E6F3FA {
    rectangle "Management Service" as mgmt
    rectangle "Annotation Service" as ann_svc
    rectangle "Mining Service" as mine_svc
}

package "Data Storage Layer" as Storage #EAF3EA {
    rectangle "MinIO Object Storage" as minio
    rectangle "MySQL Structured\nDatabase" as mysql
    rectangle "Redis Cache" as redis
}


App --> Gateway
Gateway --> Biz
Biz --> Storage


AM ...> App : Supports
AM ...> Gateway : Supports
AM ...> Biz : Supports

Infra ...> App : Supports
Infra ...> Gateway : Supports
Infra ...> Biz : Supports
Infra ...> Storage : Supports


@enduml

@startuml
skinparam componentStyle rectangle
left to right direction

skinparam defaultFontName Arial
skinparam shadowing false
skinparam ArrowColor #111111
skinparam ArrowThickness 1.5
skinparam package {
    BorderColor #777777
    BorderThickness 1
}
skinparam rectangle {
    BackgroundColor #FFFFFF
    BorderColor #111111
    BorderThickness 1
}
skinparam database {
    BackgroundColor #FFFFFF
    BorderColor #1F78D1
    BorderThickness 1
}

package "Client-side" as ClientSide #DDEEDB {
    package "Technology" as ClientTechnology {
        rectangle "Angular 7" as Angular7
    }

    package "Logic" as ClientLogic {
        rectangle "UI Components" as UIComponents {
            rectangle "HTML\nTemplates" as HtmlTemplates
            rectangle "Component\nClass" as ComponentClass
        }
        rectangle "Angular\nServices" as AngularServices
    }

    package "Data" as ClientData {
        rectangle "ngRX state store" as NgRxStore
        rectangle "View-Models\n(JSON)" as JsonViewModels
    }
}

package "Server-side" as ServerSide #DDEBFA {
    package "Technology" as ServerTechnology {
        rectangle ".NET Core\nWebAPI" as DotNetWebApi
        rectangle "Standard\nC# Classes" as StandardCSharpClasses
        rectangle "Entity\nFramework\n(ORM)" as EntityFramework
    }

    package "Logic" as ServerLogic {
        rectangle "WebAPI\nControllers" as WebApiControllers
        rectangle "Domain Services" as DomainServices {
            rectangle "PDF" as PdfService
            rectangle "CAPTCHA" as CaptchaService
            rectangle "Email" as EmailService
        }
        rectangle "DbContext" as DbContext
    }

    package "Data" as ServerData {
        rectangle "View-Models\n(C#)" as CSharpViewModels
        database "DB Entities\n(Registration, Community, etc.)" as DbEntities
    }
}

Angular7 --> DotNetWebApi : HTTP
UIComponents --> AngularServices
AngularServices --> WebApiControllers : HTTP

DotNetWebApi --> StandardCSharpClasses
StandardCSharpClasses --> EntityFramework
WebApiControllers --> DomainServices
DomainServices --> DbContext
@enduml

@startuml
' --- Configuration ---
skinparam TitleFontSize 20
skinparam shadowing false
skinparam packageStyle rectangle
skinparam ranksep 50
skinparam nodesep 20

' --- Styling ---
skinparam rectangle<<UI>> {
    BackgroundColor #e1f5fe
    BorderColor #01579b
    RoundCorner 10
}

skinparam rectangle<<Business>> {
    BackgroundColor #e8f5e9
    BorderColor #1b5e20
    RoundCorner 10
}

skinparam rectangle<<DAL>> {
    BackgroundColor #e3f2fd
    BorderColor #0d47a1
    RoundCorner 10
}

skinparam database<<Storage>> {
    BackgroundColor #eceff1
    BorderColor #263238
}

' --- Layout Direction ---
top to bottom direction

' --- UI Layer ---
package "User Interface Layer - WeChat Mini Program / Vue.js" as UI_Layer {
    rectangle "Project Info" as ProjectInfo <<UI>>
    rectangle "File Transfer" as FileTrans <<UI>>
    rectangle "Message Notification" as MsgNotif <<UI>>
    rectangle "Personal Info" as PersonalInfo <<UI>>
    rectangle "Project Registration" as ProjectReg <<UI>>
    rectangle "Post Information" as PostInfo <<UI>>
}

' --- Business Logic Layer ---
package "Business Logic Layer - Django" as Business_Logic_Layer {

    package "Project Module" as Project_Module {
        rectangle "Project Recommendation" as ProjRec <<Business>>
        rectangle "Project Info View" as ProjView <<Business>>
        rectangle "Publish Project" as ProjPub <<Business>>
        rectangle "Teacher-Student Interaction" as TutorComm <<Business>>
        rectangle "Project Search" as ProjSearch <<Business>>
        rectangle "Project Management" as ProjMgmt <<Business>>
        rectangle "Project Enrollment" as ProjEnroll <<Business>>
        rectangle "Project Message Reminder" as ProjMsgRem <<Business>>
        rectangle "Favorite Project" as ProjFav <<Business>>
    }

    package "User Module" as User_Module {
        rectangle "Login/Registration" as Auth <<Business>>
        rectangle "Resume Maintenance" as ResumeMaint <<Business>>
        rectangle "Student/Enterprise Verification" as Verification <<Business>>
        rectangle "Personal Info Maintenance" as ProfileMaint <<Business>>
        rectangle "User Search & Favorite" as UserSearch <<Business>>
    }

    package "Community Module" as Community_Module {
        rectangle "Post/Comment Display" as PostDisplay <<Business>>
        rectangle "Publish Post/Comment" as PostPub <<Business>>
        rectangle "Like/Favorite" as LikeCollect <<Business>>
    }

    package "Management Module" as Admin_Module {
        rectangle "Admin Info Maintenance" as AdminMaint <<Business>>
        rectangle "User Qualification Audit" as Audit <<Business>>
        rectangle "Post/Comment Audit" as ContentAudit <<Business>>
    }
}

' --- Data Access Layer ---
package "Data Access Layer - PyMySQL" as Data_Access_Layer {
    rectangle "File Data Parsing" as DataParsing <<DAL>>
    rectangle "Database Connection" as DBConnection <<DAL>>
}

' --- Storage Layer ---
package "Storage Layer - MySQL" as Storage_Layer {
    database "User Info DB" as UserDB <<Storage>>
    database "Project Data DB" as ProjectDB <<Storage>>
    database "Community Data DB" as CommunityDB <<Storage>>
    database "Other Data DB" as OtherDB <<Storage>>
}

' --- Relationships ---
UI_Layer --> Business_Logic_Layer
Business_Logic_Layer --> Data_Access_Layer
Data_Access_Layer --> Storage_Layer

@enduml

@startuml
' Settings for top-down layout
top to bottom direction
skinparam shadowing false
skinparam packageStyle rectangle

' Define Styles (Matching Mermaid classDefs)
skinparam rectangle {
    BackgroundColor<<presentation>> #e1f5fe
    BorderColor<<presentation>> #01579b

    BackgroundColor<<application>> #fff9c4
    BorderColor<<application>> #fbc02d

    BackgroundColor<<service>> #e8f5e9
    BorderColor<<service>> #2e7d32

    BackgroundColor<<framework>> #ffe0b2
    BorderColor<<framework>> #ef6c00

    BackgroundColor<<storage>> #f5f5f5
    BorderColor<<storage>> #616161
}

' --- Presentation Layer ---
package "Presentation Layer" as PresentationLayer {
    rectangle "Main Interface" as MainUI <<presentation>>
    rectangle "Configuration Interface" as ConfigUI <<presentation>>
    rectangle "Training Interface" as TrainUI <<presentation>>
    rectangle "Inference Interface" as InferenceUI <<presentation>>
}

' --- Application Layer ---
package "Application Layer" as ApplicationLayer {
    rectangle "Model Initialization" as ModelInit <<application>>
    rectangle "Model Training" as ModelTrain <<application>>
    rectangle "Task Inference" as TaskInference <<application>>
    rectangle "Model Management" as ModelMgmt <<application>>
}

' --- Service Layer ---
package "Service Layer" as ServiceLayer {

    package "Core Functional Modules" as CoreServices {
        ' Left-to-Right layout for core modules
        left to right direction
        package "Initialization" as InitGroup {
            rectangle "Backbone Selection" as Backbone <<service>>
            rectangle "Parameter Settings" as ParamSet <<service>>
            rectangle "Initialization Visualization" as InitViz <<service>>
        }
        package "Training" as TrainGroup {
            rectangle "Model Selection" as ModelSelT <<service>>
            rectangle "Training Hyperparams" as TrainParam <<service>>
            rectangle "Training Visualization" as TrainViz <<service>>
        }
        package "Inference" as InferGroup {
            rectangle "Model Selection" as ModelSelI <<service>>
            rectangle "Task Settings" as TaskSet <<service>>
            rectangle "Inference Visualization" as InferViz <<service>>
        }
    }

    package "System Management" as SystemMgmt {
        rectangle "Security Audit" as Security <<service>>
        rectangle "Permission Management" as Auth <<service>>
        rectangle "Logging System" as Log <<service>>
    }

    package "Infrastructure & Interfaces" as Infrastructure {
        rectangle "Business System" as BusinessSys <<service>>
        rectangle "Public Interface" as PublicAPI <<service>>
        rectangle "Service Interface" as ServiceAPI <<service>>
    }

    rectangle "Software Construction & Middleware" as SoftwareBuild <<service>>
    rectangle "Neural Network Model Management" as NNMgmt <<service>>
}

' --- MyTorch Framework Layer ---
package "MyTorch Framework Layer" as MyTorchLayer {
    package "High-Level Components" as HighLevelAPI {
        package "Neural Network" as NNModule {
            rectangle "Neural Network Tools" as NNTools <<framework>>
            rectangle "Activation Functions" as Activation <<framework>>
            rectangle "Loss Functions" as Loss <<framework>>
        }
        package "Optimization" as Optimization {
            rectangle "Optimizers" as Optimizer <<framework>>
            rectangle "LR Scheduler" as LRScheduler <<framework>>
        }
        package "Data Related" as DataModule {
            rectangle "Datasets" as Datasets <<framework>>
            rectangle "Data Loader" as DataLoader <<framework>>
        }
    }

    package "Low-Level Operations" as LowLevelOps {
        rectangle "Tensor Operations" as TensorOp <<framework>>
        rectangle "Gradient Computation" as GradCalc <<framework>>
        rectangle "Mathematical Interfaces" as MathInterface <<framework>>
    }
}

' --- Data Layer ---
package "Storage / Data Layer" as DataLayer {
    database "NN Model Data" as NNModelData <<storage>>
    database "Train/Inference History" as HistoryData <<storage>>
}

' --- Relationships ---
PresentationLayer --> ApplicationLayer
ApplicationLayer --> ServiceLayer
ServiceLayer --> MyTorchLayer
MyTorchLayer --> DataLayer

@enduml

